 13→func main() {
 14→	databaseURL := flag.String("database-url", "", "PostgreSQL connection string (falls back to DATABASE_URL env var)")
 15→	limit := flag.Int("limit", 100, "number of institutions to sample")
 16→	output := flag.String("output", "", "output file path (default: stdout, copy format only)")
 17→	outputDir := flag.String("output-dir", "", "output directory for JSON format (one file per table)")
 18→	format := flag.String("format", "copy", "output format: copy or json")
 19→	seed := flag.Int("seed", 42, "random seed for deterministic sampling")
 20→	noCompress := flag.Bool("no-compress", false, "skip xz compression for JSON output")
 21→	flag.Parse()
 22→
 23→	if *format != "copy" && *format != "json" {
 24→		fmt.Fprintln(os.Stderr, "error: --format must be 'copy' or 'json'")
 25→		os.Exit(1)
 26→	}
 27→	if *format == "json" && *outputDir == "" {
 28→		fmt.Fprintln(os.Stderr, "error: --output-dir is required for JSON format")
 29→		os.Exit(1)
 30→	}
 31→
 32→	dsn := *databaseURL
 33→	if dsn == "" {
 34→		dsn = os.Getenv("DATABASE_URL")
 35→	}
 36→	if dsn == "" {
 37→		fmt.Fprintln(os.Stderr, "error: --database-url flag or DATABASE_URL env var is required")
 38→		os.Exit(1)
 39→	}
 40→	if *limit <= 0 {
 41→		fmt.Fprintln(os.Stderr, "error: --limit must be positive")
 42→		os.Exit(1)
 43→	}
 44→
 45→	ctx := context.Background()
 46→
 47→	conn, err := pgx.Connect(ctx, dsn)
 48→	if err != nil {
 49→		fmt.Fprintf(os.Stderr, "error: connect to database: %v\n", err)
 50→		os.Exit(1)
 51→	}
 52→	defer conn.Close(ctx)
 53→
 54→	fmt.Fprintf(os.Stderr, "sampling %d institutions (seed=%d)...\n", *limit, *seed)
 55→	unitIDs, err := sampleInstitutions(ctx, conn, *limit, *seed)
 56→	if err != nil {
 57→		fmt.Fprintf(os.Stderr, "error: %v\n", err)
 58→		os.Exit(1)
 59→	}
 60→	fmt.Fprintf(os.Stderr, "sampled %d institutions\n", len(unitIDs))
 61→
 62→	useGeoJSON := *format == "json"
 63→	fmt.Fprintln(os.Stderr, "extracting dependent tables...")
 64→	tables, err := extractAll(ctx, conn, unitIDs, useGeoJSON)
 65→	if err != nil {
 66→		fmt.Fprintf(os.Stderr, "error: %v\n", err)
 67→		os.Exit(1)
 68→	}
 69→
 70→	switch *format {
 71→	case "json":
 72→		fmt.Fprintln(os.Stderr, "writing JSON...")
 73→		if err := writeJSON(*outputDir, tables, !*noCompress); err != nil {
 74→			fmt.Fprintf(os.Stderr, "error: write output: %v\n", err)
 75→			os.Exit(1)
 76→		}
 77→	case "copy":
 78→		var w *os.File
 79→		if *output != "" {
 80→			w, err = os.Create(*output)
 81→			if err != nil {
 82→				fmt.Fprintf(os.Stderr, "error: create output file: %v\n", err)
 83→				os.Exit(1)
 84→			}
 85→			defer w.Close()
 86→		} else {
 87→			w = os.Stdout
 88→		}
 89→
 90→		fmt.Fprintln(os.Stderr, "writing COPY SQL...")
 91→		if err := writeCopySQL(w, tables, *seed, *limit); err != nil {
 92→			fmt.Fprintf(os.Stderr, "error: write output: %v\n", err)
 93→			os.Exit(1)
 94→		}
 95→	}
 96→
 97→	for _, t := range tables {
 98→		fmt.Fprintf(os.Stderr, "  %s.%s: %d rows\n", t.Schema, t.Table, len(t.Rows))
 99→	}
100→	fmt.Fprintln(os.Stderr, "done")
101→}
