10→// sampleInstitutions returns a deterministic pseudo-random sample of unit_ids
11→// from search_base.institution, ordered by md5(unit_id || seed).
12→func sampleInstitutions(ctx context.Context, conn *pgx.Conn, limit int, seed int) ([]string, error) {
13→	query := `SELECT unit_id FROM search_base.institution ORDER BY md5(unit_id || $1) LIMIT $2`
14→	rows, err := conn.Query(ctx, query, fmt.Sprintf("%d", seed), limit)
15→	if err != nil {
16→		return nil, fmt.Errorf("samplesql: query institutions: %w", err)
17→	}
18→	defer rows.Close()
19→
20→	var unitIDs []string
21→	for rows.Next() {
22→		var id string
23→		if err := rows.Scan(&id); err != nil {
24→			return nil, fmt.Errorf("samplesql: scan unit_id: %w", err)
25→		}
26→		unitIDs = append(unitIDs, id)
27→	}
28→	if err := rows.Err(); err != nil {
29→		return nil, fmt.Errorf("samplesql: iterate institutions: %w", err)
30→	}
31→	return unitIDs, nil
32→}
