 10→// writeCopySQL writes all extracted table data in PostgreSQL COPY text format.
 11→func writeCopySQL(w io.Writer, tables []tableData, seed, limit int) error {
 12→	// Header comment
 13→	if _, err := fmt.Fprintf(w, "-- samplesql: generated %s (seed=%d, limit=%d)\n",
 14→		time.Now().UTC().Format(time.RFC3339), seed, limit); err != nil {
 15→		return err
 16→	}
 17→	if _, err := fmt.Fprintln(w); err != nil {
 18→		return err
 19→	}
 20→
 21→	for _, td := range tables {
 22→		if len(td.Rows) == 0 {
 23→			continue
 24→		}
 25→
 26→		qualifiedName := fmt.Sprintf("%s.%s", td.Schema, td.Table)
 27→		colList := strings.Join(td.Columns, ", ")
 28→
 29→		if _, err := fmt.Fprintf(w, "COPY %s (%s) FROM stdin;\n", qualifiedName, colList); err != nil {
 30→			return err
 31→		}
 32→
 33→		for _, row := range td.Rows {
 34→			for i, val := range row {
 35→				if i > 0 {
 36→					if _, err := fmt.Fprint(w, "\t"); err != nil {
 37→						return err
 38→					}
 39→				}
 40→				if _, err := fmt.Fprint(w, formatCopyValue(val)); err != nil {
 41→					return err
 42→				}
 43→			}
 44→			if _, err := fmt.Fprintln(w); err != nil {
 45→				return err
 46→			}
 47→		}
 48→
 49→		if _, err := fmt.Fprintln(w, `\.`); err != nil {
 50→			return err
 51→		}
 52→		if _, err := fmt.Fprintln(w); err != nil {
 53→			return err
 54→		}
 55→	}
 56→
 57→	return nil
 58→}
 59→
 60→// formatCopyValue formats a single value for PostgreSQL COPY text format.
 61→func formatCopyValue(v any) string {
 62→	if v == nil {
 63→		return `\N`
 64→	}
 65→
 66→	switch val := v.(type) {
 67→	case []byte:
 68→		// Binary data (e.g. PostGIS geography) — output as hex
 69→		return fmt.Sprintf(`\x%x`, val)
 70→	case string:
 71→		return escapeCopyText(val)
 72→	case time.Time:
 73→		return val.Format("2006-01-02 15:04:05.999-07")
 74→	case bool:
 75→		if val {
 76→			return "t"
 77→		}
 78→		return "f"
 79→	case map[string]any:
 80→		// JSONB values are returned as map by pgx
 81→		return escapeCopyText(marshalJSON(val))
 82→	case []any:
 83→		// JSONB array values
 84→		return escapeCopyText(marshalJSON(val))
 85→	default:
 86→		return escapeCopyText(fmt.Sprintf("%v", val))
 87→	}
 88→}
 89→
 90→// escapeCopyText escapes special characters for PostgreSQL COPY text format.
 91→func escapeCopyText(s string) string {
 92→	s = strings.ReplaceAll(s, `\`, `\\`)
 93→	s = strings.ReplaceAll(s, "\t", `\t`)
 94→	s = strings.ReplaceAll(s, "\n", `\n`)
 95→	s = strings.ReplaceAll(s, "\r", `\r`)
 96→	return s
 97→}
 98→
 99→// marshalJSON converts a Go value to a JSON string without importing encoding/json
100→// in the function signature — keeps it simple.
101→func marshalJSON(v any) string {
102→	// Use fmt for simple cases; for maps/slices, use encoding/json
103→	b, err := jsonMarshal(v)
104→	if err != nil {
105→		return fmt.Sprintf("%v", v)
106→	}
107→	return string(b)
108→}
