package db

import (
	"context"
	"fmt"
	"log/slog"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
)

const maxConnectAttempts = 3

// Connect creates a pgxpool.Pool, pings the database, and returns the pool.
// It retries up to maxConnectAttempts times with exponential backoff.
func Connect(ctx context.Context, databaseURL string) (*pgxpool.Pool, error) {
	cfg, err := pgxpool.ParseConfig(databaseURL)
	if err != nil {
		return nil, fmt.Errorf("db: failed to parse database URL: %w", err)
	}

	var pool *pgxpool.Pool
	for attempt := 1; attempt <= maxConnectAttempts; attempt++ {
		pool, err = pgxpool.NewWithConfig(ctx, cfg)
		if err != nil {
			slog.Warn("db: connect attempt failed", "attempt", attempt, "error", err)
			time.Sleep(time.Duration(attempt) * time.Second)
			continue
		}

		if err = pool.Ping(ctx); err != nil {
			pool.Close()
			slog.Warn("db: ping attempt failed", "attempt", attempt, "error", err)
			time.Sleep(time.Duration(attempt) * time.Second)
			continue
		}

		stat := pool.Stat()
		slog.Info("db: connected",
			"attempt", attempt,
			"max_conns", stat.MaxConns(),
		)
		return pool, nil
	}

	return nil, fmt.Errorf("db: failed to connect after %d attempts: %w", maxConnectAttempts, err)
}
